using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF9 breaking change: Migrate() now manages its own transactions and
    // execution strategy internally. Wrapping it in a user transaction throws
    // MigrationsUserTransactionWarning. Remove the outer transaction + strategy.
    void ApplyMigrations(AppDbContext db)
    {
        db.Database.Migrate();
    }
}

