using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 breaking change #1: Discriminator property renamed from
        // "Discriminator" to "$type". Existing documents use the old name,
        // so configure it explicitly to preserve compatibility.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // EF9 breaking change #2: The JSON `id` property no longer contains
        // the discriminator value by default (was "Session|<key>", now just "<key>").
        // Existing documents still have the old format, so opt back in.
        modelBuilder.Entity<Session>().HasDiscriminatorInJsonId();
    }
}

class Session
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

using Microsoft.EntityFrameworkCore;

class CosmosService
{
    // EF9 breaking change: Sync I/O on the Cosmos provider now throws
    // (CosmosEventId.SyncNotSupported). All queries and SaveChanges
    // calls must use their async counterparts.

    // BEFORE (throws in EF9):
    //   var sessions = db.Sessions.ToList();
    //   db.SaveChanges();

    // AFTER:
    async Task RunAsync(CosmosDbContext db)
    {
        var sessions = await db.Sessions.ToListAsync();

        db.Sessions.Add(new Session { Id = "1", Name = "Keynote" });
        await db.SaveChangesAsync();
    }
}

